using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.CosmosDBForPostgreSql;
using Azure.ResourceManager.CosmosDBForPostgreSql.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.CosmosDBForPostgreSql.Tests.Samples
{
    public class Sample1_Clusters : SamplesBase<CosmosDBForPostgreSqlManagementTestEnvironment>
    {
        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateCluster()
        {
            #region Snippet:CreateCosmosDBForPostgreSqlCluster
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            // Retrieve the subscription and resource group
            string subscriptionId = "00000000-0000-0000-0000-000000000000";
            string resourceGroupName = "myResourceGroup";
            ResourceGroupResource resourceGroup = await client
                .GetSubscriptionResource(new ResourceIdentifier($"/subscriptions/{subscriptionId}"))
                .GetResourceGroupAsync(resourceGroupName);

            // Prepare cluster create parameters
            CosmosDBForPostgreSqlClusterData data = new CosmosDBForPostgreSqlClusterData(
                new Azure.Core.AzureLocation("eastus"))
            {
                PostgresqlVersion = "15",
                AdministratorLoginPassword = "myP@ssword1",
                CoordinatorStorageQuotaInMb = 524288,
                CoordinatorVCores = 4,
                NodeCount = 2,
                NodeStorageQuotaInMb = 524288,
                NodeVCores = 4,
            };

            CosmosDBForPostgreSqlClusterCollection clusters = resourceGroup.GetCosmosDBForPostgreSqlClusters();
            ArmOperation<CosmosDBForPostgreSqlClusterResource> operation = await clusters
                .CreateOrUpdateAsync(WaitUntil.Completed, "myCluster", data);
            CosmosDBForPostgreSqlClusterResource cluster = operation.Value;
            Console.WriteLine($"Cluster provisioning state: {cluster.Data.ProvisioningState}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task ListClusters()
        {
            #region Snippet:ListCosmosDBForPostgreSqlClusters
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "00000000-0000-0000-0000-000000000000";
            SubscriptionResource subscription = await client
                .GetSubscriptionResource(new ResourceIdentifier($"/subscriptions/{subscriptionId}"))
                .GetAsync();

            await foreach (CosmosDBForPostgreSqlClusterResource cluster in subscription
                .GetCosmosDBForPostgreSqlClustersAsync())
            {
                Console.WriteLine(cluster.Data.Name);
            }
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateFirewallRule()
        {
            #region Snippet:CreateCosmosDBForPostgreSqlFirewallRule
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "00000000-0000-0000-0000-000000000000";
            string resourceGroupName = "myResourceGroup";
            string clusterName = "myCluster";

            ResourceGroupResource resourceGroup = await client
                .GetSubscriptionResource(new ResourceIdentifier($"/subscriptions/{subscriptionId}"))
                .GetResourceGroupAsync(resourceGroupName);

            CosmosDBForPostgreSqlClusterResource cluster = await resourceGroup
                .GetCosmosDBForPostgreSqlClusterAsync(clusterName);

            CosmosDBForPostgreSqlFirewallRuleData ruleData =
                new CosmosDBForPostgreSqlFirewallRuleData("0.0.0.0", "255.255.255.255");

            ArmOperation<CosmosDBForPostgreSqlFirewallRuleResource> operation = await cluster
                .GetCosmosDBForPostgreSqlFirewallRules()
                .CreateOrUpdateAsync(WaitUntil.Completed, "allowAll", ruleData);

            Console.WriteLine($"Firewall rule provisioning state: {operation.Value.Data.ProvisioningState}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task UpdateConfiguration()
        {
            #region Snippet:UpdateCosmosDBForPostgreSqlConfiguration
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "00000000-0000-0000-0000-000000000000";
            string resourceGroupName = "myResourceGroup";
            string clusterName = "myCluster";
            string configurationName = "array_nulls";

            ResourceGroupResource resourceGroup = await client
                .GetSubscriptionResource(new ResourceIdentifier($"/subscriptions/{subscriptionId}"))
                .GetResourceGroupAsync(resourceGroupName);

            CosmosDBForPostgreSqlClusterResource cluster = await resourceGroup
                .GetCosmosDBForPostgreSqlClusterAsync(clusterName);

            CosmosDBForPostgreSqlConfigurationResource configuration = await cluster
                .GetCosmosDBForPostgreSqlConfigurationAsync(configurationName);

            Console.WriteLine($"Configuration '{configurationName}' current value: {configuration.Data.Value}");
            #endregion
        }
    }
}
```

